onBanner":false},"rawBlobUrl":"https://github.com/PHPMailer/PHPMailer/raw/refs/heads/master/src/PHPMailer.php","renderImageOrRaw":false,"shortPath":null,"symbolsEnabled":true,"tabSize":4,"topBannersInfo":{"overridingGlobalFundingFile":false,"globalPreferredFundingPath":null,"showInvalidCitationWarning":false,"citationHelpUrl":"https://docs.github.com/github/creating-cloning-and-archiving-repositories/creating-a-repository-on-github/about-citation-files","actionsOnboardingTip":null},"truncated":false,"viewable":true,"workflowRedirectUrl":null},"copilotInfo":null,"copilotAccessAllowed":true,"copilotSpacesEnabled":true,"modelsAccessAllowed":false,"modelsRepoIntegrationEnabled":false,"isMarketplaceEnabled":true},"codeViewBlobLayoutRoute.StyledBlob":{"rawLines":["\u003c?php","","/**"," * PHPMailer - PHP email creation and transport class."," * PHP Version 5.5."," *"," * @see https://github.com/PHPMailer/PHPMailer/ The PHPMailer GitHub project"," *"," * @author    Marcus Bointon (Synchro/coolbru) \u003cphpmailer@synchromedia.co.uk\u003e"," * @author    Jim Jagielski (jimjag) \u003cjimjag@gmail.com\u003e"," * @author    Andy Prevost (codeworxtech) \u003ccodeworxtech@users.sourceforge.net\u003e"," * @author    Brent R. Matzelle (original founder)"," * @copyright 2012 - 2020 Marcus Bointon"," * @copyright 2010 - 2012 Jim Jagielski"," * @copyright 2004 - 2009 Andy Prevost"," * @license   https://www.gnu.org/licenses/old-licenses/lgpl-2.1.html GNU Lesser General Public License"," * @note      This program is distributed in the hope that it will be useful - WITHOUT"," * ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or"," * FITNESS FOR A PARTICULAR PURPOSE."," */","","namespace PHPMailer\\PHPMailer;","","/**"," * PHPMailer - PHP email creation and transport class."," *"," * @author Marcus Bointon (Synchro/coolbru) \u003cphpmailer@synchromedia.co.uk\u003e"," * @author Jim Jagielski (jimjag) \u003cjimjag@gmail.com\u003e"," * @author Andy Prevost (codeworxtech) \u003ccodeworxtech@users.sourceforge.net\u003e"," * @author Brent R. Matzelle (original founder)"," */","class PHPMailer","{","    const CHARSET_ASCII = 'us-ascii';","    const CHARSET_ISO88591 = 'iso-8859-1';","    const CHARSET_UTF8 = 'utf-8';","","    const CONTENT_TYPE_PLAINTEXT = 'text/plain';","    const CONTENT_TYPE_TEXT_CALENDAR = 'text/calendar';","    const CONTENT_TYPE_TEXT_HTML = 'text/html';","    const CONTENT_TYPE_MULTIPART_ALTERNATIVE = 'multipart/alternative';","    const CONTENT_TYPE_MULTIPART_MIXED = 'multipart/mixed';","    const CONTENT_TYPE_MULTIPART_RELATED = 'multipart/related';","","    const ENCODING_7BIT = '7bit';","    const ENCODING_8BIT = '8bit';","    const ENCODING_BASE64 = 'base64';","    const ENCODING_BINARY = 'binary';","    const ENCODING_QUOTED_PRINTABLE = 'quoted-printable';","","    const ENCRYPTION_STARTTLS = 'tls';","    const ENCRYPTION_SMTPS = 'ssl';","","    const ICAL_METHOD_REQUEST = 'REQUEST';","    const ICAL_METHOD_PUBLISH = 'PUBLISH';","    const ICAL_METHOD_REPLY = 'REPLY';","    const ICAL_METHOD_ADD = 'ADD';","    const ICAL_METHOD_CANCEL = 'CANCEL';","    const ICAL_METHOD_REFRESH = 'REFRESH';","    const ICAL_METHOD_COUNTER = 'COUNTER';","    const ICAL_METHOD_DECLINECOUNTER = 'DECLINECOUNTER';","","    /**","     * Email priority.","     * Options: null (default), 1 = High, 3 = Normal, 5 = low.","     * When null, the header is not set at all.","     *","     * @var int|null","     */","    public $Priority;","","    /**","     * The character set of the message.","     *","     * @var string","     */","    public $CharSet = self::CHARSET_ISO88591;","","    /**","     * The MIME Content-type of the message.","     *","     * @var string","     */","    public $ContentType = self::CONTENT_TYPE_PLAINTEXT;","","    /**","     * The message encoding.","     * Options: \"8bit\", \"7bit\", \"binary\", \"base64\", and \"quoted-printable\".","     *","     * @var string","     */","    public $Encoding = self::ENCODING_8BIT;","","    /**","     * Holds the most recent mailer error message.","     *","     * @var string","     */","    public $ErrorInfo = '';","","    /**","     * The From email address for the message.","     *","     * @var string","     */","    public $From = '';","","    /**","     * The From name of the message.","     *","     * @var string","     */","    public $FromName = '';","","    /**","     * The envelope sender of the message.","     * This will usually be turned into a Return-Path header by the receiver,","     * and is the address that bounces will be sent to.","     * If not empty, will be passed via `-f` to sendmail or as the 'MAIL FROM' value over SMTP.","     *","     * @var string","     */","    public $Sender = '';","","    /**","     * The Subject of the message.","     *","     * @var string","     */","    public $Subject = '';","","    /**","     * An HTML or plain text message body.","     * If HTML then call isHTML(true).","     *","     * @var string","     */","    public $Body = '';","","    /**","     * The plain-text message body.","     * This body can be read by mail clients that do not have HTML email","     * capability such as mutt \u0026 Eudora.","     * Clients that can read HTML will view the normal Body.","     *","     * @var string","     */","    public $AltBody = '';","","    /**","     * An iCal message part body.","     * Only supported in simple alt or alt_inline message types","     * To generate iCal event structures, use classes like EasyPeasyICS or iCalcreator.","     *","     * @see https://kigkonsult.se/iCalcreator/","     *","     * @var string","     */","    public $Ical = '';","","    /**","     * Value-array of \"method\" in Contenttype header \"text/calendar\"","     *","     * @var string[]","     */","    protected static $IcalMethods = [","        self::ICAL_METHOD_REQUEST,","        self::ICAL_METHOD_PUBLISH,","        self::ICAL_METHOD_REPLY,","        self::ICAL_METHOD_ADD,","        self::ICAL_METHOD_CANCEL,","        self::ICAL_METHOD_REFRESH,","        self::ICAL_METHOD_COUNTER,","        self::ICAL_METHOD_DECLINECOUNTER,","    ];","","    /**","     * The complete compiled MIME message body.","     *","     * @var string","     */","    protected $MIMEBody = '';","","    /**","     * The complete compiled MIME message headers.","     *","     * @var string","     */","    protected $MIMEHeader = '';","","    /**","     * Extra headers that createHeader() doesn't fold in.","     *","     * @var string","     */","    protected $mailHeader = '';","","    /**","     * Word-wrap the message body to this number of chars.","     * Set to 0 to not wrap. A useful value here is 78, for RFC2822 section 2.1.1 compliance.","     *","     * @see static::STD_LINE_LENGTH","     *","     * @var int","     */","    public $WordWrap = 0;","","    /**","     * Which method to use to send mail.","     * Options: \"mail\", \"sendmail\", or \"smtp\".","     *","     * @var string","     */","    public $Mailer = 'mail';","","    /**","     * The path to the sendmail program.","     *","     * @var string","     */","    public $Sendmail = '/usr/sbin/sendmail';","","    /**","     * Whether mail() uses a fully sendmail-compatible MTA.","     * One which supports sendmail's \"-oi -f\" options.","     *","     * @var bool","     */","    public $UseSendmailOptions = true;","","    /**","     * The email address that a reading confirmation should be sent to, also known as read receipt.","     *","     * @var string","     */","    public $ConfirmReadingTo = '';","","    /**","     * The hostname to use in the Message-ID header and as default HELO string.","     * If empty, PHPMailer attempts to find one with, in order,","     * $_SERVER['SERVER_NAME'], gethostname(), php_uname('n'), or the value","     * 'localhost.localdomain'.","     *","     * @see PHPMailer::$Helo","     *","     * @var string","     */","    public $Hostname = '';","","    /**","     * An ID to be used in the Message-ID header.","     * If empty, a unique id will be generated.","     * You can set your own, but it must be in the format \"\u003cid@domain\u003e\",","     * as defined in RFC5322 section 3.6.4 or it will be ignored.","     *","     * @see https://www.rfc-editor.org/rfc/rfc5322#section-3.6.4","     *","     * @var string","     */","    public $MessageID = '';","","    /**","     * The message Date to be used in the Date header.","     * If empty, the current date will be added.","     *","     * @var string","     */","    public $MessageDate = '';","","    /**","     * SMTP hosts.","     * Either a single hostname or multiple semicolon-delimited hostnames.","     * You can also specify a different port","     * for each host by using this format: [hostname:port]","     * (e.g. \"smtp1.example.com:25;smtp2.example.com\").","     * You can also specify encryption type, for example:","     * (e.g. \"tls://smtp1.example.com:587;ssl://smtp2.example.com:465\").","     * Hosts will be tried in order.","     *","     * @var string","     */","    public $Host = 'localhost';","","    /**","     * The default SMTP server port.","     *","     * @var int","     */","    public $Port = 25;","","    /**","     * The SMTP HELO/EHLO name used for the SMTP connection.","     * Default is $Hostname. If $Hostname is empty, PHPMailer attempts to find","     * one with the same method described above for $Hostname.","     *","     * @see PHPMailer::$Hostname","     *","     * @var string","     */","    public $Helo = '';","","    /**","     * What kind of encryption to use on the SMTP connection.","     * Options: '', static::ENCRYPTION_STARTTLS, or static::ENCRYPTION_SMTPS.","     *","     * @var string","     */","    public $SMTPSecure = '';","","    /**","     * Whether to enable TLS encryption automatically if a server supports it,","     * even if `SMTPSecure` is not set to 'tls'.","     * Be aware that in PHP \u003e= 5.6 this requires that the server's certificates are valid.","     *","     * @var bool","     */","    public $SMTPAutoTLS = true;","","    /**","     * Whether to use SMTP authentication.","     * Uses the Username and Password properties.","     *","     * @see PHPMailer::$Username","     * @see PHPMailer::$Password","     *","     * @var bool","     */","    public $SMTPAuth = false;","","    /**","     * Options array passed to stream_context_create when connecting via SMTP.","     *","     * @var array","     */","    public $SMTPOptions = [];","","    /**","     * SMTP username.","     *","     * @var string","     */","    public $Username = '';","","    /**","     * SMTP password.","     *","     * @var string","     */","    public $Password = '';","","    /**","     * SMTP authentication type. Options are CRAM-MD5, LOGIN, PLAIN, XOAUTH2.","     * If not specified, the first one from that list that the server supports will be selected.","     *","     * @var string","     */","    public $AuthType = '';","","    /**","     * SMTP SMTPXClient command attributes","     *","     * @var array","     */","    protected $SMTPXClient = [];","","    /**","     * An implementation of the PHPMailer OAuthTokenProvider interface.","     *","     * @var OAuthTokenProvider","     */","    protected $oauth;","","    /**","     * The SMTP server timeout in seconds.","     * Default of 5 minutes (300sec) is from RFC2821 section 4.5.3.2.","     *","     * @var int","     */","    public $Timeout = 300;","","    /**","     * Comma separated list of DSN notifications","     * 'NEVER' under no circumstances a DSN must be returned to the sender.","     *         If you use NEVER all other notifications will be ignored.","     * 'SUCCESS' will notify you when your mail has arrived at its destination.","     * 'FAILURE' will arrive if an error occurred during delivery.","     * 'DELAY'   will notify you if there is an unusual delay in delivery, but the actual","     *           delivery's outcome (success or failure) is not yet decided.","     *","     * @see https://www.rfc-editor.org/rfc/rfc3461.html#section-4.1 for more information about NOTIFY","     */","    public $dsn = '';","","    /**","     * SMTP class debug output mode.","     * Debug output level.","     * Options:","     * @see SMTP::DEBUG_OFF: No output","     * @see SMTP::DEBUG_CLIENT: Client messages","     * @see SMTP::DEBUG_SERVER: Client and server messages","     * @see SMTP::DEBUG_CONNECTION: As SERVER plus connection status","     * @see SMTP::DEBUG_LOWLEVEL: Noisy, low-level data output, rarely needed","     *","     * @see SMTP::$do_debug","     *","     * @var int","     */","    public $SMTPDebug = 0;","","    /**","     * How to handle debug output.","     * Options:","     * * `echo` Output plain-text as-is, appropriate for CLI","     * * `html` Output escaped, line breaks converted to `\u003cbr\u003e`, appropriate for browser output","     * * `error_log` Output to error log as configured in php.ini","     * By default PHPMailer will use `echo` if run from a `cli` or `cli-server` SAPI, `html` otherwise.","     * Alternatively, you can provide a callable expecting two params: a message string and the debug level:","     *","     * ```php","     * $mail-\u003eDebugoutput = function($str, $level) {echo \"debug level $level; message: $str\";};","     * ```","     *","     * Alternatively, you can pass in an instance of a PSR-3 compatible logger, though only `debug`","     * level output is used:","     *","     * ```php","     * $mail-\u003eDebugoutput = new myPsr3Logger;","     * ```","     *","     * @see SMTP::$Debugoutput","     *","     * @var string|callable|\\Psr\\Log\\LoggerInterface","     */","    public $Debugoutput = 'echo';","","    /**","     * Whether to keep the SMTP connection open after each message.","     * If this is set to true then the connection will remain open after a send,","     * and closing the connection will require an explicit call to smtpClose().","     * It's a good idea to use this if you are sending multiple messages as it reduces overhead.","     * See the mailing list example for how to use it.","     *","     * @var bool","     */","    public $SMTPKeepAlive = false;","","    /**","     * Whether to split multiple to addresses into multiple messages","     * or send them all in one message.","     * Only supported in `mail` and `sendmail` transports, not in SMTP.","     *","     * @var bool","     *","     * @deprecated 6.0.0 PHPMailer isn't a mailing list manager!","     */","    public $SingleTo = false;","","    /**","     * Storage for addresses when SingleTo is enabled.","     *","     * @var array","     */","    protected $SingleToArray = [];","","    /**","     * Whether to generate VERP addresses on send.","     * Only applicable when sending via SMTP.","     *","     * @see https://en.wikipedia.org/wiki/Variable_envelope_return_path","     * @see https://www.postfix.org/VERP_README.html Postfix VERP info","     *","     * @var bool","     */","    public $do_verp = false;","","    /**","     * Whether to allow sending messages with an empty body.","     *","     * @var bool","     */","    public $AllowEmpty = false;","","    /**","     * DKIM selector.","     *","     * @var string","     */","    public $DKIM_selector = '';","","    /**","     * DKIM Identity.","     * Usually the email address used as the source of the email.","     *","     * @var string","     */","    public $DKIM_identity = '';","","    /**","     * DKIM passphrase.","     * Used if your key is encrypted.","     *","     * @var string","     */","    public $DKIM_passphrase = '';","","    /**","     * DKIM signing domain name.","     *","     * @example 'example.com'","     *","     * @var string","     */","    public $DKIM_domain = '';","","    /**","     * DKIM Copy header field values for diagnostic use.","     *","     * @var bool","     */","    public $DKIM_copyHeaderFields = true;","","    /**","     * DKIM Extra signing headers.","     *","     * @example ['List-Unsubscribe', 'List-Help']","     *","     * @var array","     */","    public $DKIM_extraHeaders = [];","","    /**","     * DKIM private key file path.","     *","     * @var string","     */","    public $DKIM_private = '';","","    /**","     * DKIM private key string.","     *","     * If set, takes precedence over `$DKIM_private`.","     *","     * @var string","     */","    public $DKIM_private_string = '';","","    /**","     * Callback Action function name.","     *","     * The function that handles the result of the send email action.","     * It is called out by send() for each email sent.","     *","     * Value can be any php callable: https://www.php.net/is_callable","     *","     * Parameters:","     *   bool $result           result of the send action","     *   array   $to            email addresses of the recipients","     *   array   $cc            cc email addresses","     *   array   $bcc           bcc email addresses","     *   string  $subject       the subject","     *   string  $body          the email body","     *   string  $from          email address of sender","     *   string  $extra         extra information of possible use","     *                          'smtp_transaction_id' =\u003e last smtp transaction id","     *","     * @var callable|callable-string","     */","    public $action_function = '';","","    /**","     * What to put in the X-Mailer header.","     * Options: An empty string for PHPMailer default, whitespace/null for none, or a string to use.","     *","     * @var string|null","     */","    public $XMailer = '';","","    /**","     * Which validator to use by default when validating email addresses.","     * May be a callable to inject your own validator, but there are several built-in validators.","     * The default validator uses PHP's FILTER_VALIDATE_EMAIL filter_var option.","     *","     * If CharSet is UTF8, the validator is left at the default value,","     * and you send to addresses that use non-ASCII local parts, then","     * PHPMailer automatically changes to the 'eai' validator.","     *","     * @see PHPMailer::validateAddress()","     *","     * @var string|callable","     */","    public static $validator = 'php';","","    /**","     * An instance of the SMTP sender class.","     *","     * @var SMTP","     */","    protected $smtp;","","    /**","     * The array of 'to' names and addresses.","     *","     * @var array","     */","    protected $to = [];","","    /**","     * The array of 'cc' names and addresses.","     *","     * @var array","     */","    protected $cc = [];","","    /**","     * The array of 'bcc' names and addresses.","     *","     * @var array","     */","    protected $bcc = [];","","    /**","     * The array of reply-to names and addresses.","     *","     * @var array","     */","    protected $ReplyTo = [];","","    /**","     * An array of all kinds of addresses.","     * Includes all of $to, $cc, $bcc.","     *","     * @see PHPMailer::$to","     * @see PHPMailer::$cc","     * @see PHPMailer::$bcc","     *","     * @var array","     */","    protected $all_recipients = [];","","    /**","     * An array of names and addresses queued for validation.","     * In send(), valid and non duplicate entries are moved to $all_recipients","     * and one of $to, $cc, or $bcc.","     * This array is used only for addresses with IDN.","     *","     * @see PHPMailer::$to","     * @see PHPMailer::$cc","     * @see PHPMailer::$bcc","     * @see PHPMailer::$all_recipients","     *","     * @var array","     */","    protected $RecipientsQueue = [];","","    /**","     * An array of reply-to names and addresses queued for validation.","     * In send(), valid and non duplicate entries are moved to $ReplyTo.","     * This array is used only for addresses with IDN.","     *","     * @see PHPMailer::$ReplyTo","     *","     * @var array","     */","    protected $ReplyToQueue = [];","","    /**","     * Whether the need for SMTPUTF8 has been detected. Set by","     * preSend() if necessary.","     *","     * @var bool","     */","    public $UseSMTPUTF8 = false;","","    /**","     * The array of attachments.","     *","     * @var array","     */","    protected $attachment = [];","","    /**","     * The array of custom headers.","     *","     * @var array","     */","    protected $CustomHeader = [];","","    /**","     * The most recent Message-ID (including angular brackets).","     *","     * @var string","     */","    protected $lastMessageID = '';","","    /**","     * The message's MIME type.","     *","     * @var string","     */","    protected $message_type = '';","","    /**","     * The array of MIME boundary strings.","     *","     * @var array","     */","    protected $boundary = [];","","    /**","     * The array of available text strings for the current language.","     *","     * @var array","     */","    protected static $language = [];","","    /**","     * The number of errors encountered.","     *","     * @var int","     */","    protected $error_count = 0;","","    /**","     * The S/MIME certificate file path.","     *","     * @var string","     */","    protected $sign_cert_file = '';","","    /**","     * The S/MIME key file path.","     *","     * @var string","     */","    protected $sign_key_file = '';","","    /**","     * The optional S/MIME extra certificates (\"CA Chain\") file path.","     *","     * @var string","     */","    protected $sign_extracerts_file = '';","","    /**","     * The S/MIME password for the key.","     * Used only if the key is encrypted.","     *","     * @var string","     */","    protected $sign_key_pass = '';","","    /**","     * Whether to throw exceptions for errors.","     *","     * @var bool","     */","    protected $exceptions = false;","","    /**","     * Unique ID used for message ID and boundaries.","     *","     * @var string","     */","    protected $uniqueid = '';","","    /**","     * The PHPMailer Version number.","     *","     * @var string","     */","    const VERSION = '7.0.2';","","    /**","     * Error severity: message only, continue processing.","     *","     * @var int","     */","    const STOP_MESSAGE = 0;","","    /**","     * Error severity: message, likely ok to continue processing.","     *","     * @var int","     */","    const STOP_CONTINUE = 1;","","    /**","     * Error severity: message, plus full stop, critical error reached.","     *","     * @var int","     */","    const STOP_CRITICAL = 2;","","    /**","     * The SMTP standard CRLF line break.","     * If you want to change line break format, change static::$LE, not this.","     */","    const CRLF = \"\\r\\n\";","","    /**","     * \"Folding White Space\" a white space string used for line folding.","     */","    const FWS = ' ';","","    /**","     * SMTP RFC standard line ending; Carriage Return, Line Feed.","     *","     * @var string","     */","    protected static $LE = self::CRLF;","","    /**","     * The maximum line length supported by mail().","     *","     * Background: mail() will sometimes corrupt messages","     * with headers longer than 65 chars, see #818.","     *","     * @var int","     */","    const MAIL_MAX_LINE_LENGTH = 63;","","    /**","     * The maximum line length allowed by RFC 2822 section 2.1.1.","     *","     * @var int","     */","    const MAX_LINE_LENGTH = 998;","","    /**","     * The lower maximum line length allowed by RFC 2822 section 2.1.1.","     * This length does NOT include the line break","     * 76 means that lines will be 77 or 78 chars depending on whether","     * the line break format is LF or CRLF; both are valid.","     *","     * @var int","     */","    const STD_LINE_LENGTH = 76;","","    /**","     * Constructor.","     *","     * @param bool $exceptions Should we throw external exceptions?","     */","    public function __construct($exceptions = null)","    {","        if (null !== $exceptions) {","            $this-\u003eexceptions = (bool) $exceptions;","        }","        //Pick an appropriate debug output format automatically","        $this-\u003eDebugoutput = (strpos(PHP_SAPI, 'cli') !== false ? 'echo' : 'html');","    }","","    /**","     * Destructor.","     */","    public function __destruct()","    {","        //Close any open SMTP connection nicely","        $this-\u003esmtpClose();","    }","","    /**","     * Call mail() in a safe_mode-aware fashion.","     * Also, unless sendmail_path points to sendmail (or something that","     * claims to be sendmail), don't pass params (not a perfect fix,","     * but it will do).","     *","     * @param string      $to      To","     * @param string      $subject Subject","     * @param string      $body    Message Body","     * @param string      $header  Additional Header(s)","     * @param string|null $params  Params","     *","     * @return bool","     */","    private function mailPassthru($to, $subject, $body, $header, $params)","    {","        //Check overloading of mail function to avoid double-encoding","        // phpcs:ignore PHPCompatibility.IniDirectives.RemovedIniDirectives.mbstring_func_overloadDeprecatedRemoved","        if ((int)ini_get('mbstring.func_overload') \u0026 1) {","            $subject = $this-\u003esecureHeader($subject);","        } else {","            $subject = $this-\u003eencodeHeader($this-\u003esecureHeader($subject));","        }","        //Calling mail() with null params breaks","        $this-\u003eedebug('Sending with mail()');","        $this-\u003eedebug('Sendmail path: ' . ini_get('sendmail_path'));","        $this-\u003eedebug(\"Envelope sender: {$this-\u003eSender}\");","        $this-\u003eedebug(\"To: {$to}\");","        $this-\u003eedebug(\"Subject: {$subject}\");","        $this-\u003eedebug(\"Headers: {$header}\");","        if (!$this-\u003eUseSendmailOptions || null === $params) {","            $result = @mail($to, $subject, $body, $header);","        } else {","            $this-\u003eedebug(\"Additional params: {$params}\");","            $result = @mail($to, $subject, $body, $header, $params);","        }","        $this-\u003eedebug('Result: ' . ($result ? 'true' : 'false'));","        return $result;","    }","","    /**","     * Output debugging info via a user-defined method.","     * Only generates output if debug output is enabled.","     *","     * @see PHPMailer::$Debugoutput","     * @see PHPMailer::$SMTPDebug","     *","     * @param string $str","     */","    protected function edebug($str)","    {","        if ($this-\u003eSMTPDebug \u003c= 0) {","            return;","        }","        //Is this a PSR-3 logger?","        if ($this-\u003eDebugoutput instanceof \\Psr\\Log\\LoggerInterface) {","            $this-\u003eDebugoutput-\u003edebug(rtrim($str, \"\\r\\n\"));","","            return;","        }","        //Avoid clash with built-in function names","        if (is_callable($this-\u003eDebugoutput) \u0026\u0026 !in_array($this-\u003eDebugoutput, ['error_log', 'html', 'echo'])) {","            call_user_func($this-\u003eDebugoutput, $str, $this-\u003eSMTPDebug);","","            return;","        }","        switch ($this-\u003eDebugoutput) {","            case 'error_log':","                //Don't output, just log","                /** @noinspection ForgottenDebugOutputInspection */","                error_log($str);","                break;","            case 'html':","                //Cleans up output a bit for a better looking, HTML-safe output","                echo htmlentities(","                    preg_replace('/[\\r\\n]+/', '', $str),","                    ENT_QUOTES,","                    'UTF-8'","                ), \"\u003cbr\u003e\\n\";","                break;","            case 'echo':","            default:","                //Normalize line breaks","                $str = preg_replace('/\\r\\n|\\r/m', \"\\n\", $str);","                echo gmdate('Y-m-d H:i:s'),","                \"\\t\",","                    //Trim trailing space","                trim(","                    //Indent for readability, except for trailing break","                    str_replace(","                        \"\\n\",","                        \"\\n                   \\t                  \",","                        trim($str)","                    )","                ),","                \"\\n\";","        }","    }","","    /**","     * Sets message type to HTML or plain.","     *","     * @param bool $isHtml True for HTML mode","     */","    public function isHTML($isHtml = true)","    {","        if ($isHtml) {","            $this-\u003eContentType = static::CONTENT_TYPE_TEXT_HTML;","        } else {","            $this-\u003eContentType = static::CONTENT_TYPE_PLAINTEXT;","        }","    }","","    /**","     * Send messages using SMTP.","     */","    public function isSMTP()","    {","        $this-\u003eMailer = 'smtp';","    }","","    /**","     * Send messages using PHP's mail() function.","     */","    public function isMail()","    {","        $this-\u003eMailer = 'mail';","    }","","    /**","     * Extract sendmail path and parse to deal with known parameters.","     *","     * @param string $sendmailPath The sendmail path as set in php.ini","     *","     * @return string The sendmail path without the known parameters","     */","    private function parseSendmailPath($sendmailPath)","    {","        $sendmailPath = trim((string)$sendmailPath);","        if ($sendmailPath === '') {","            return $sendmailPath;","        }","","        $parts = preg_split('/\\s+/', $sendmailPath);","        if (empty($parts)) {","            return $sendmailPath;","        }","","        $command = array_shift($parts);","        $remainder = [];","","        // Parse only -t, -i, -oi and -f parameters.","        for ($i = 0; $i \u003c count($parts); ++$i) {","            $part = $parts[$i];","            if (preg_match('/^-(i|oi|t)$/', $part, $matches)) {","                continue;","            }","            if (preg_match('/^-f(.*)$/', $part, $matches)) {","                $address = $matches[1];","                if ($address === '' \u0026\u0026 isset($parts[$i + 1]) \u0026\u0026 strpos($parts[$i + 1], '-') !== 0) {","                    $address = $parts[++$i];","                }","                $this-\u003eSender = $address;","                continue;","            }","","            $remainder[] = $part;","        }","","        // The params that are not parsed are added back to the command.","        if (!empty($remainder)) {","            $command .= ' ' . implode(' ', $remainder);","        }","","        return $command;","    }","","    /**","     * Send messages using $Sendmail.","     */","    public function isSendmail()","    {","        $ini_sendmail_path = ini_get('sendmail_path');","","        if (false === stripos($ini_sendmail_path, 'sendmail')) {","            $ini_sendmail_path = '/usr/sbin/sendmail';","        }","        $this-\u003eSendmail = $this-\u003eparseSendmailPath($ini_sendmail_path);","        $this-\u003eMailer = 'sendmail';","    }","","    /**","     * Send messages using qmail.","     */","    public function isQmail()","    {","        $ini_sendmail_path = ini_get('sendmail_path');","","        if (false === stripos($ini_sendmail_path, 'qmail')) {","            $ini_sendmail_path = '/var/qmail/bin/qmail-inject';","        }","        $this-\u003eSendmail = $this-\u003eparseSendmailPath($ini_sendmail_path);","        $this-\u003eMailer = 'qmail';","    }","","    /**","     * Add a \"To\" address.","     *","     * @param string $address The email address to send to","     * @param string $name","     *","     * @throws Exception","     *","     * @return bool true on success, false if address already used or invalid in some way","     */","    public function addAddress($address, $name = '')","    {","        return $this-\u003eaddOrEnqueueAnAddress('to', $address, $name);","    }","","    /**","     * Add a \"CC\" address.","     *","     * @param string $address The email address to send to","     * @param string $name","     *","     * @throws Exception","     *","     * @return bool true on success, false if address already used or invalid in some way","     */","    public function addCC($address, $name = '')","    {","        return $this-\u003eaddOrEnqueueAnAddress('cc', $address, $name);","    }","","    /**","     * Add a \"BCC\" address.","     *","     * @param string $address The email address to send to","     * @param string $name","     *","     * @throws Exception","     *","     * @return bool true on success, false if address already used or invalid in some way","     */","    public function addBCC($address, $name = '')","    {","        return $this-\u003eaddOrEnqueueAnAddress('bcc', $address, $name);","    }","","    /**","     * Add a \"Reply-To\" address.","     *","     * @param string $address The email address to reply to","     * @param string $name","     *","     * @throws Exception","     *","     * @return bool true on success, false if address already used or invalid in some way","     */","    public function addReplyTo($address, $name = '')","    {","        return $this-\u003eaddOrEnqueueAnAddress('Reply-To', $address, $name);","    }","","    /**","     * Add an address to one of the recipient arrays or to the ReplyTo array. Because PHPMailer","     * can't validate addresses with an IDN without knowing the PHPMailer::$CharSet (that can still","     * be modified after calling this function), addition of such addresses is delayed until send().","     * Addresses that have been added already return false, but do not throw exceptions.","     *","     * @param string $kind    One of 'to', 'cc', 'bcc', or 'Reply-To'","     * @param string $address The email address","     * @param string $name    An optional username associated with the address","     *","     * @throws Exception","     *","     * @return bool true on success, false if address already used or invalid in some way","     */","    protected function addOrEnqueueAnAddress($kind, $address, $name)","    {","        $pos = false;","        if ($address !== null) {","            $address = trim($address);","            $pos = strrpos($address, '@');","        }","        if (false === $pos) {","            //At-sign is missing.","            $error_message = sprintf(","                '%s (%s): %s',","                self::lang('invalid_address'),","                $kind,","                $address","            );","            $this-\u003esetError($error_message);","            $this-\u003eedebug($error_message);","            if ($this-\u003eexceptions) {","                throw new Exception($error_message);","            }","","            return false;","        }","        if ($name !== null \u0026\u0026 is_string($name)) {","            $name = trim(preg_replace('/[\\r\\n]+/', '', $name)); //Strip breaks and trim","        } else {","            $name = '';","        }","        $params = [$kind, $address, $name];","        //Enqueue addresses with IDN until we know the PHPMailer::$CharSet.","        //Domain is assumed to be whatever is after the last @ symbol in the address","        if ($this-\u003ehas8bitChars(substr($address, ++$pos))) {","            if (static::idnSupported()) {","                if ('Reply-To' !== $kind) {","                    if (!array_key_exists($address, $this-\u003eRecipientsQueue)) {","                        $this-\u003eRecipientsQueue[$address] = $params;","","                        return true;","                    }","                } elseif (!array_key_exists($address, $this-\u003eReplyToQueue)) {","                    $this-\u003eReplyToQueue[$address] = $params;","","                    return true;","                }","            }","            //We have an 8-bit domain, but we are missing the necessary extensions to support it","            //Or we are already sending to this address","            return false;","        }","","        //Immediately add standard addresses without IDN.","        return call_user_func_array([$this, 'addAnAddress'], $params);","    }","","    /**","     * Set the boundaries to use for delimiting MIME parts.","     * If you override this, ensure you set all 3 boundaries to unique values.","     * The default boundaries include a \"=_\" sequence which cannot occur in quoted-printable bodies,","     * as suggested by https://www.rfc-editor.org/rfc/rfc2045#section-6.7","     *","     * @return void","     */","    public function setBoundaries()","    {","        $this-\u003euniqueid = $this-\u003egenerateId();","        $this-\u003eboundary[1] = 'b1=_' . $this-\u003euniqueid;","        $this-\u003eboundary[2] = 'b2=_' . $this-\u003euniqueid;","        $this-\u003eboundary[3] = 'b3=_' . $this-\u003euniqueid;","    }","","    /**","     * Add an address to one of the recipient arrays or to the ReplyTo array.","     * Addresses that have been added already return false, but do not throw exceptions.","     *","     * @param string $kind    One of 'to', 'cc', 'bcc', or 'ReplyTo'","     * @param string $address The email address to send, resp. to reply to","     * @param string $name","     *","     * @throws Exception","     *","     * @return bool true on success, false if address already used or invalid in some way","     */","    protected function addAnAddress($kind, $address, $name = '')","    {","        if (","            self::$validator === 'php' \u0026\u0026","            ((bool) preg_match('/[\\x80-\\xFF]/', $address))","        ) {","            //The caller has not altered the validator and is sending to an address","            //with UTF-8, so assume that they want UTF-8 support instead of failing","            $this-\u003eCharSet = self::CHARSET_UTF8;","            self::$validator = 'eai';","        }","        if (!in_array($kind, ['to', 'cc', 'bcc', 'Reply-To'])) {","            $error_message = sprintf(","                '%s: %s',","                self::lang('Invalid recipient kind'),","                $kind","            );","            $this-\u003esetError($error_message);","            $this-\u003eedebug($error_message);","            if ($this-\u003eexceptions) {","                throw new Exception($error_message);","            }","","            return false;","        }","        if (!static::validateAddress($address)) {","            $error_message = sprintf(","                '%s (%s): %s',","                self::lang('invalid_address'),","                $kind,","                $address","            );","            $this-\u003esetError($error_message);","            $this-\u003eedebug($error_message);","            if ($this-\u003eexceptions) {","                throw new Exception($error_message);","            }","","            return false;","        }","        if ('Reply-To' !== $kind) {","            if (!array_key_exists(strtolower($address), $this-\u003eall_recipients)) {","                $this-\u003e{$kind}[] = [$address, $name];","                $this-\u003eall_recipients[strtolower($address)] = true;","","                return true;","            }","        } else {","            foreach ($this-\u003eReplyTo as $replyTo) {","                if (0 === strcasecmp($replyTo[0], $address)) {","                    return false;","                }","            }","            $this-\u003eReplyTo[] = [$address, $name];","","            return true;","        }","        return false;","    }","","    /**","     * Parse and validate a string containing one or more RFC822-style comma-separated email addresses","     * of the form \"display name \u003caddress\u003e\" into an array of name/address pairs.","     * Uses the imap_rfc822_parse_adrlist function if the IMAP extension is available.","     * Note that quotes in the name part are removed.","     *","     * @see https://www.andrew.cmu.edu/user/agreen1/testing/mrbs/web/Mail/RFC822.php A more careful implementation","     *","     * @param string $addrstr The address list string","     * @param null   $useimap Unused. Argument has been deprecated in PHPMailer 6.11.0.","     *                        Previously this argument determined whether to use","     *                        the IMAP extension to parse the list and accepted a boolean value.","     * @param string $charset The charset to use when decoding the address list string.","     *","     * @return array","     */","    public static function parseAddresses($addrstr, $useimap = null, $charset = self::CHARSET_ISO88591)","    {","        if ($useimap !== null) {","            trigger_error(self::lang('deprecated_argument') . '$useimap', E_USER_DEPRECATED);","        }","        $addresses = [];","        if (function_exists('imap_rfc822_parse_adrlist')) {","            //Use this built-in parser if it's available","            // phpcs:ignore PHPCompatibility.FunctionUse.RemovedFunctions.imap_rfc822_parse_adrlistRemoved -- wrapped in function_exists()","            $list = imap_rfc822_parse_adrlist($addrstr, '');","            // Clear any potential IMAP errors to get rid of notices being thrown at end of script.","            // phpcs:ignore PHPCompatibility.FunctionUse.RemovedFunctions.imap_errorsRemoved -- wrapped in function_exists()","            imap_errors();","            foreach ($list as $address) {","                if (","                    '.SYNTAX-ERROR.' !== $address-\u003ehost \u0026\u0026","                    static::validateAddress($address-\u003emailbox . '@' . $address-\u003ehost)","                ) {","                    //Decode the name part if it's present and maybe encoded","                    if (","                        property_exists($address, 'personal')","                        \u0026\u0026 is_string($address-\u003epersonal)","                        \u0026\u0026 $address-\u003epersonal !== ''","                    ) {","                        $address-\u003epersonal = static::decodeHeader($address-\u003epersonal, $charset);","                    }","","                    $addresses[] = [","                        'name' =\u003e (property_exists($address, 'personal') ? $address-\u003epersonal : ''),","                        'address' =\u003e $address-\u003emailbox . '@' . $address-\u003ehost,","                    ];","                }","            }","        } else {","            //Use this simpler parser","            $addresses = static::parseSimplerAddresses($addrstr, $charset);","        }","","        return $addresses;","    }","","    /**","     * Parse a string containing one or more RFC822-style comma-separated email addresses","     * with the form \"display name \u003caddress\u003e\" into an array of name/address pairs.","     * Uses a simpler parser that does not require the IMAP extension but doesnt support","     * the full RFC822 spec. For full RFC822 support, use the PHP IMAP extension.","     *","     * @param string $addrstr The address list string","     * @param string $charset The charset to use when decoding the address list string.","     *","     * @return array","     */","    protected static function parseSimplerAddresses($addrstr, $charset)","    {","        // Emit a runtime notice to recommend using the IMAP extension for full RFC822 parsing","        trigger_error(self::lang('imap_recommended'), E_USER_NOTICE);","","        $addresses = [];","        $list = explode(',', $addrstr);","        foreach ($list as $address) {","            $address = trim($address);","            //Is there a separate name part?","            if (strpos($address, '\u003c') === false) {","                //No separate name, just use the whole thing","                if (static::validateAddress($address)) {","                    $addresses[] = [","                        'name' =\u003e '',","                        'address' =\u003e $address,","                    ];","                }","            } else {","                $parsed = static::parseEmailString($address);","                $email = $parsed['email'];","                if (static::validateAddress($email)) {","                    $name = static::decodeHeader($parsed['name'], $charset);","                    $addresses[] = [","                        //Remove any surrounding quotes and spaces from the name","                        'name' =\u003e trim($name, '\\'\" '),","                        'address' =\u003e $email,","                    ];","                }","            }","        }","","        return $addresses;","    }","","    /**","     * Parse a string containing an email address with an optional name","     * and divide it into a name and email address.","     *","     * @param string $input The email with name.","     *","     * @return array{name: string, email: string}","     */","    private static function parseEmailString($input)","    {","        $input = trim((string)$input);","","        if ($input === '') {","            return ['name' =\u003e '', 'email' =\u003e ''];","        }","","        $pattern = '/^\\s*(?:(?:\"([^\"]*)\"|\\'([^\\']*)\\'|([^\u003c]*?))\\s*)?\u003c\\s*([^\u003e]+)\\s*\u003e\\s*$/';","        if (preg_match($pattern, $input, $matches)) {","            $name = '';","            // Double quotes including special scenarios.","            if (isset($matches[1]) \u0026\u0026 $matches[1] !== '') {","                $name = $matches[1];","            // Single quotes including special scenarios.","            } elseif (isset($matches[2]) \u0026\u0026 $matches[2] !== '') {","                $name = $matches[2];","            // Simplest scenario, name and email are in the format \"Name \u003cemail\u003e\".","            } elseif (isset($matches[3])) {","                $name = trim($matches[3]);","            }","","            return ['name' =\u003e $name, 'email' =\u003e trim($matches[4])];","        }","","        return ['name' =\u003e '', 'email' =\u003e $input];","    }","","    /**","     * Set the From and FromName properties.","     *","     * @param string $address","     * @param string $name","     * @param bool   $auto    Whether to also set the Sender address, defaults to true","     *","     * @throws Exception","     *","     * @return bool","     */","    public function setFrom($address, $name = '', $auto = true)","    {","        if (is_null($name)) {","            //Helps avoid a deprecation warning in the preg_replace() below","            $name = '';","        }","        $address = trim((string)$address);","        $name = trim(preg_replace('/[\\r\\n]+/', '', $name)); //Strip breaks and trim","        //Don't validate now addresses with IDN. Will be done in send().","        $pos = strrpos($address, '@');","        if (","            (false === $pos)","            || ((!$this-\u003ehas8bitChars(substr($address, ++$pos)) || !static::idnSupported())","            \u0026\u0026 !static::validateAddress($address))","        ) {","            $error_message = sprintf(","                '%s (From): %s',","                self::lang('invalid_address'),","                $address","            );","            $this-\u003esetError($error_message);","            $this-\u003eedebug($error_message);","            if ($this-\u003eexceptions) {","                throw new Exception($error_message);","            }","","            return false;","        }","        $this-\u003eFrom = $address;","        $this-\u003eFromName = $name;","        if ($auto \u0026\u0026 empty($this-\u003eSender)) {","            $this-\u003eSender = $address;","        }","","        return true;","    }","","    /**","     * Return the Message-ID header of the last email.","     * Technically this is the value from the last time the headers were created,","     * but it's also the message ID of the last sent message except in","     * pathological cases.","     *","     * @return string","     */","    public function getLastMessageID()","    {","        return $this-\u003elastMessageID;","    }","","    /**","     * Check that a string looks like an email address.","     * Validation patterns supported:","     * * `auto` Pick best pattern automatically;","     * * `pcre8` Use the squiloople.com pattern, requires PCRE \u003e 8.0;","     * * `pcre` Use old PCRE implementation;","     * * `php` Use PHP built-in FILTER_VALIDATE_EMAIL;","     * * `html5` Use the pattern given by the HTML5 spec for 'email' type form input elements.","     * * `eai` Use a pattern similar to the HTML5 spec for 'email' and to firefox, extended to support EAI (RFC6530).","     * * `noregex` Don't use a regex: super fast, really dumb.","     * Alternatively you may pass in a callable to inject your own validator, for example:","     *","     * ```php","     * PHPMailer::validateAddress('user@example.com', function($address) {","     *     return (strpos($address, '@') !== false);","     * });","     * ```","     *","     * You can also set the PHPMailer::$validator static to a callable, allowing built-in methods to use your validator.","     *","     * @param string          $address       The email address to check","     * @param string|callable $patternselect Which pattern to use","     *","     * @return bool","     */","    public static function validateAddress($address, $patternselect = null)","    {","        if (null === $patternselect) {","            $patternselect = static::$validator;","        }","        //Don't allow strings as callables, see SECURITY.md and CVE-2021-3603","        if (is_callable($patternselect) \u0026\u0026 !is_string($patternselect)) {","            return call_user_func($patternselect, $address);","        }","        //Reject line breaks in addresses; it's valid RFC5322, but not RFC5321","        if (strpos($address, \"\\n\") !== false || strpos($address, \"\\r\") !== false) {","            return false;","        }","        switch ($patternselect) {","            case 'pcre': //Kept for BC","            case 'pcre8':","                /*","                 * A more complex and more permissive version of the RFC5322 regex on which FILTER_VALIDATE_EMAIL","                 * is based.","                 * In addition to the addresses allowed by filter_var, also permits:","                 *  * dotless domains: `a@b`","                 *  * comments: `1234 @ local(blah) .machine .example`","                 *  * quoted elements: `'\"test blah\"@example.org'`","                 *  * numeric TLDs: `a@b.123`","                 *  * unbracketed IPv4 literals: `a@192.168.0.1`","                 *  * IPv6 literals: 'first.last@[IPv6:a1::]'","                 * Not all of these will necessarily work for sending!","                 *","                 * @copyright 2009-2010 Michael Rushton","                 * Feel free to use and redistribute this code. But please keep this copyright notice.","                 */","                return (bool) preg_match(","                    '/^(?!(?\u003e(?1)\"?(?\u003e\\\\\\[ -~]|[^\"])\"?(?1)){255,})(?!(?\u003e(?1)\"?(?\u003e\\\\\\[ -~]|[^\"])\"?(?1)){65,}@)' .","                    '((?\u003e(?\u003e(?\u003e((?\u003e(?\u003e(?\u003e\\x0D\\x0A)?[\\t ])+|(?\u003e[\\t ]*\\x0D\\x0A)?[\\t ]+)?)(\\((?\u003e(?2)' .","                    '(?\u003e[\\x01-\\x08\\x0B\\x0C\\x0E-\\'*-\\[\\]-\\x7F]|\\\\\\[\\x00-\\x7F]|(?3)))*(?2)\\)))+(?2))|(?2))?)' .","                    '([!#-\\'*+\\/-9=?^-~-]+|\"(?\u003e(?2)(?\u003e[\\x01-\\x08\\x0B\\x0C\\x0E-!#-\\[\\]-\\x7F]|\\\\\\[\\x00-\\x7F]))*' .","                    '(?2)\")(?\u003e(?1)\\.(?1)(?4))*(?1)@(?!(?1)[a-z0-9-]{64,})(?1)(?\u003e([a-z0-9](?\u003e[a-z0-9-]*[a-z0-9])?)' .","                    '(?\u003e(?1)\\.(?!(?1)[a-z0-9-]{64,})(?1)(?5)){0,126}|\\[(?:(?\u003eIPv6:(?\u003e([a-f0-9]{1,4})(?\u003e:(?6)){7}' .","                    '|(?!(?:.*[a-f0-9][:\\]]){8,})((?6)(?\u003e:(?6)){0,6})?::(?7)?))|(?\u003e(?\u003eIPv6:(?\