/usD',","                    $address","                );","            case 'php':","            default:","                return filter_var($address, FILTER_VALIDATE_EMAIL) !== false;","        }","    }","","    /**","     * Tells whether IDNs (Internationalized Domain Names) are supported or not. This requires the","     * `intl` and `mbstring` PHP extensions.","     *","     * @return bool `true` if required functions for IDN support are present","     */","    public static function idnSupported()","    {","        return function_exists('idn_to_ascii') \u0026\u0026 function_exists('mb_convert_encoding');","    }","","    /**","     * Converts IDN in given email address to its ASCII form, also known as punycode, if possible.","     * Important: Address must be passed in same encoding as currently set in PHPMailer::$CharSet.","     * This function silently returns unmodified address if:","     * - No conversion is necessary (i.e. domain name is not an IDN, or is already in ASCII form)","     * - Conversion to punycode is impossible (e.g. required PHP functions are not available)","     *   or fails for any reason (e.g. domain contains characters not allowed in an IDN).","     *","     * @see PHPMailer::$CharSet","     *","     * @param string $address The email address to convert","     *","     * @return string The encoded address in ASCII form","     */","    public function punyencodeAddress($address)","    {","        //Verify we have required functions, CharSet, and at-sign.","        $pos = strrpos($address, '@');","        if (","            !empty($this-\u003eCharSet) \u0026\u0026","            false !== $pos \u0026\u0026","            static::idnSupported()","        ) {","            $domain = substr($address, ++$pos);","            //Verify CharSet string is a valid one, and domain properly encoded in this CharSet.","            if ($this-\u003ehas8bitChars($domain) \u0026\u0026 @mb_check_encoding($domain, $this-\u003eCharSet)) {","                