      //Create error message for any bad addresses","        if (count($bad_rcpt) \u003e 0) {","            $errstr = '';","            foreach ($bad_rcpt as $bad) {","                $errstr .= $bad['to'] . ': ' . $bad['error'];","            }","            throw new Exception(self::lang('recipients_failed') . $errstr, self::STOP_CONTINUE);","        }","","        return true;","    }","","    /**","     * Initiate a connection to an SMTP server.","     * Returns false if the operation failed.","     *","     * @param array $options An array of options compatible with stream_context_create()","     *","     * @throws Exception","     *","     * @uses \\PHPMailer\\PHPMailer\\SMTP","     *","     * @return bool","     */","    public function smtpConnect($options = null)","    {","        if (null === $this-\u003esmtp) {","            $this-\u003esmtp = $this-\u003egetSMTPInstance();","        }","","        //If no options are provided, use whatever is set in the instance","        if (null === $options) {","            $options = $this-\u003eSMTPOptions;","        }","","        //Already connected?","        if ($this-\u003esmtp-\u003econnected()) {","            return true;","        }","","        $this-\u003esmtp-\u003esetTimeout($this-\u003eTimeout);","        $this-\u003esmtp-\u003esetDebugLevel($this-\u003eSMTPDebug);","        $this-\u003esmtp-\u003esetDebugOutput($this-\u003eDebugoutput);","        $this-\u003esmtp-\u003esetVerp($this-\u003edo_verp);","        $this-\u003esmtp-\u003esetSMTPUTF8($this-\u003eUseSMTPUTF8);","        if ($this-\u003eHost === null) {","            $this-\u003eHost = 'localhost';","        }","        $hosts = explode(';', $this-\u003eHost);","        $lastexception = null;","","        foreach ($hosts as $hostentry) {","            $hostinfo = [];","            if (","                !preg_match(","                    '/^(?:(ssl|tls):\\/\\/)?(.+?)(?::(\\d+))?$/',","                    trim($hostentry),","                    