= $hostinfo[2];","            $port = $this-\u003ePort;","            if (","                array_key_exists(3, $hostinfo) \u0026\u0026","                is_numeric($hostinfo[3]) \u0026\u0026","                $hostinfo[3] \u003e 0 \u0026\u0026","                $hostinfo[3] \u003c 65536","            ) {","                $port = (int) $hostinfo[3];","            }","            if ($this-\u003esmtp-\u003econnect($prefix . $host, $port, $this-\u003eTimeout, $options)) {","                try {","                    if ($this-\u003eHelo) {","                        $hello = $this-\u003eHelo;","                    } else {","                        $hello = $this-\u003eserverHostname();","                    }","                    $this-\u003esmtp-\u003ehello($hello);","                    //Automatically enable TLS encryption if:","                    //* it's not disabled","                    //* we are not connecting to localhost","                    //* we have openssl extension","                    //* we are not already using SSL","                    //* the server offers STARTTLS","                    if (","                        $this-\u003eSMTPAutoTLS \u0026\u0026","                        $this-\u003eHost !== 'localhost' \u0026\u0026","                        $sslext \u0026\u0026","                        $secure !== 'ssl' \u0026\u0026","                        $this-\u003esmtp-\u003egetServerExt('STARTTLS')","                    ) {","                        $tls = true;","                    }","                    if ($tls) {","                        if (!$this-\u003esmtp-\u003estartTLS()) {","                            $message = $this-\u003egetSmtpErrorMessage('connect_host');","                            throw new Exception($message);","                        }","                        //We must resend EHLO after TLS negotiation","                        $this-\u003esmtp-\u003ehello($hello);","                    }","                    i