com', 'Joe User']","     *","     * @return string","     */","    public function addrFormat($addr)","    {","        if (!isset($addr[1]) || ($addr[1] === '')) { //No name provided","            return $this-\u003esecureHeader($addr[0]);","        }","","        return $this-\u003eencodeHeader($this-\u003esecureHeader($addr[1]), 'phrase') .","            ' \u003c' . $this-\u003esecureHeader($addr[0]) . '\u003e';","    }","","    /**","     * Word-wrap message.","     * For use with mailers that do not automatically perform wrapping","     * and for quoted-printable encoded messages.","     * Original written by philippe.","     *","     * @param string $message The message to wrap","     * @param int    $length  The line length to wrap to","     * @param bool   $qp_mode Whether to run in Quoted-Printable mode","     *","     * @return string","     */","    public function wrapText($message, $length, $qp_mode = false)","    {","        if ($qp_mode) {","            $soft_break = sprintf(' =%s', static::$LE);","        } else {","            $soft_break = static::$LE;","        }","        //If utf-8 encoding is used, we will need to make sure we don't","        //split multibyte characters when we wrap","        $is_utf8 = static::CHARSET_UTF8 === strtolower($this-\u003eCharSet);","        $lelen = strlen(static::$LE);","        $crlflen = strlen(static::$LE);","","        $message = static::normalizeBreaks($message);","        //Remove a trailing line break","        if (substr($message, -$lelen) === static::$LE) {","            $message = substr($message, 0, -$lelen);","        }","","        //Split message into lines","        $lines = explode(static::$LE, $message);","        //Message will be rebuilt in here","        $message = '';","        foreach ($lines as $line) {","            $words = explode(' ', $line);","            $buf = '';","            $firstword = true;","            foreach ($words as $word) {","                if ($qp_mode \u0026\u0026 (st