 and the charset (\"` =?\u003ccharset\u003e?[QB]?\u003ccontent\u003e?=`\").","        $overhead = 8 + strlen($charset);","","        if ('mail' === $this-\u003eMailer) {","            $maxlen = static::MAIL_MAX_LINE_LENGTH - $overhead;","        } else {","            $maxlen = static::MAX_LINE_LENGTH - $overhead;","        }","","        //Select the encoding that produces the shortest output and/or prevents corruption.","        if ($matchcount \u003e strlen($str) / 3) {","            //More than 1/3 of the content needs encoding, use B-encode.","            $encoding = 'B';","        } elseif ($matchcount \u003e 0) {","            //Less than 1/3 of the content needs encoding, use Q-encode.","            $encoding = 'Q';","        } elseif (strlen($str) \u003e $maxlen) {","            //No encoding needed, but value exceeds max line length, use Q-encode to prevent corruption.","            $encoding = 'Q';","        } else {","            //No reformatting needed","            $encoding = false;","        }","","        switch ($encoding) {","            case 'B':","                if ($this-\u003ehasMultiBytes($str)) {","                    //Use a custom function which correctly encodes and wraps long","                    //multibyte strings without breaking lines within a character","                    $encoded = $this-\u003ebase64EncodeWrapMB($str, \"\\n\");","                } else {","                    $encoded = base64_encode($str);","                    $maxlen -= $maxlen % 4;","                    $encoded = trim(chunk_split($encoded, $maxlen, \"\\n\"));","                }","                $encoded = preg_replace('/^(.*)$/m', ' =?' . $charset . \"?$encoding?\\\\1?=\", $encoded);","                break;","            case 'Q':","                $encoded = $this-\u003eencodeQ($str, $position);","                $encoded = $this-\u003ewrapText($encoded, $maxlen, true);","                $encoded = str_replace('=' . static::$LE, \"\\n\", trim($encoded