ttern;","                break;","        }","        $matches = [];","        if (preg_match_all(\"/[{$pattern}]/\", $encoded, $matches)) {","            //If the string contains an '=', make sure it's the first thing we replace","            //so as to avoid double-encoding","            $eqkey = array_search('=', $matches[0], true);","            if (false !== $eqkey) {","                unset($matches[0][$eqkey]);","                array_unshift($matches[0], '=');","            }","            foreach (array_unique($matches[0]) as $char) {","                $encoded = str_replace($char, '=' . sprintf('%02X', ord($char)), $encoded);","            }","        }","        //Replace spaces with _ (more readable than =20)","        //RFC 2047 section 4.2(2)","        return str_replace(' ', '_', $encoded);","    }","","    /**","     * Add a string or binary attachment (non-filesystem).","     * This method can be used to attach ascii or binary data,","     * such as a BLOB record from a database.","     *","     * @param string $string      String attachment data","     * @param string $filename    Name of the attachment","     * @param string $encoding    File encoding (see $Encoding)","     * @param string $type        File extension (MIME) type","     * @param string $disposition Disposition to use","     *","     * @throws Exception","     *","     * @return bool True on successfully adding an attachment","     */","    public function addStringAttachment(","        $string,","        $filename,","        $encoding = self::ENCODING_BASE64,","        $type = '',","        $disposition = 'attachment'","    ) {","        try {","            //If a MIME type is not specified, try to work it out from the file name","            if ('' === $type) {","                $type = static::filenameToType($filename);","            }","","            if (!$this-\u003evalidateEncoding($encoding)) {","                throw new Exception(self::lang('encoding') . $encoding);","            }","","            //Append to $attachment array","            $this-\u003eattachment[] = [","                0 =\u003e $string,","                1 =\u003e $filename,","                2 =\u003e static::mb_pathinfo($filename, PATHINFO_BASENAME),","                3 =\u003e $encoding,","                4 =\u003e $type,","                5 =\u003e true, //isStringAttachment","                6 =\u003e $disposition,","                7 =\u003e 0,","            ];","        } catch (Exception $exc) {","            $this-\u003esetError($exc-\u003egetMessage());","            $this-\u003eedebug($exc-\u003egetMessage());","            if ($this-\u003eexceptions) {","                throw $exc;","            }","","            return false;","        }","","        return true;","    }","","    /**","     * Add an embedded (inline) attachment from a file.","     * This can include images, sounds, and just about any other document type.","     * These differ from 'regular' attachments in that they are intended to be","     * displayed inline with the message, not just attached for download.","     * This is used in HTML messages that embed the images","     * the HTML refers to using the `$cid` value in `img` tags, for example `\u003cimg src=\"cid:mylogo\"\u003e`.","     * Never use a user-supplied path to a file!","     *","     * @param string $path        Path to the attachment","     * @param string $cid         Content ID of the attachment; Use this to reference","     *                            the content when using an embedded image in HTML","     * @param string $name        Overrides the attachment filename","     * @param string $encoding    File encoding (see $Encoding) defaults to `base64`","     * @param string $type        File MIME type (by default mapped from the `$path` filename's extension)","     * @param string $disposition Disposition to use: `inline` (default) or `attachment`","     *                            (unlikely you want this – {@se