} catch (Exception $exc) {","            $this-\u003esetError($exc-\u003egetMessage());","            $this-\u003eedebug($exc-\u003egetMessage());","            if ($this-\u003eexceptions) {","                throw $exc;","            }","","            return false;","        }","","        return true;","    }","","    /**","     * Validate encodings.","     *","     * @param string $encoding","     *","     * @return bool","     */","    protected function validateEncoding($encoding)","    {","        return in_array(","            $encoding,","            [","                self::ENCODING_7BIT,","                self::ENCODING_QUOTED_PRINTABLE,","                self::ENCODING_BASE64,","                self::ENCODING_8BIT,","                self::ENCODING_BINARY,","            ],","            true","        );","    }","","    /**","     * Check if an embedded attachment is present with this cid.","     *","     * @param string $cid","     *","     * @return bool","     */","    protected function cidExists($cid)","    {","        foreach ($this-\u003eattachment as $attachment) {","            if ('inline' === $attachment[6] \u0026\u0026 $cid === $attachment[7]) {","                return true;","            }","        }","","        return false;","    }","","    /**","     * Check if an inline attachment is present.","     *","     * @return bool","     */","    public function inlineImageExists()","    {","        foreach ($this-\u003eattachment as $attachment) {","            if ('inline' === $attachment[6]) {","                return true;","            }","        }","","        return false;","    }","","    /**","     * Check if an attachment (non-inline) is present.","     *","     * @return bool","     */","    public function attachmentExists()","    {","        foreach ($this-\u003eattachment as $attachment) {","            if ('attachment' === $attachment[6]) {","                return true;","            }","        }","","        return false;"