"        if (null === $value \u0026\u0026 strpos($name, ':') !== false) {","            //Value passed in as name:value","            list($name, $value) = explode(':', $name, 2);","        }","        $name = trim($name);","        $value = (null === $value) ? '' : trim($value);","","        $replaced = false;","        foreach ($this-\u003eCustomHeader as $k =\u003e $pair) {","            if ($pair[0] == $name) {","                if ($replaced) {","                    unset($this-\u003eCustomHeader[$k]);","                    continue;","                }","                if (strpbrk($name . $value, \"\\r\\n\") !== false) {","                    if ($this-\u003eexceptions) {","                        throw new Exception(self::lang('invalid_header'));","                    }","","                    return false;","                }","                $this-\u003eCustomHeader[$k] = [$name, $value];","                $replaced = true;","            }","        }","","        return true;","    }","","    /**","     * Add an error message to the error container.","     *","     * @param string $msg","     */","    protected function setError($msg)","    {","        ++$this-\u003eerror_count;","        if ('smtp' === $this-\u003eMailer \u0026\u0026 null !== $this-\u003esmtp) {","            $lasterror = $this-\u003esmtp-\u003egetError();","            if (!empty($lasterror['error'])) {","                $msg .= ' ' . self::lang('smtp_error') . $lasterror['error'];","                if (!empty($lasterror['detail'])) {","                    $msg .= ' ' . self::lang('smtp_detail') . $lasterror['detail'];","                }","                if (!empty($lasterror['smtp_code'])) {","                    $msg .= ' ' . self::lang('smtp_code') . $lasterror['smtp_code'];","                }","                if (!empty($lasterror['smtp_code_ex'])) {","                    $msg .= ' ' . self::lang('smtp_code_ex') . $lasterror['smtp_code_ex'];","                }","            }","        }","        $this-\u003eErrorInfo = $msg;","    }","","    /**","     * Return an RFC 822 formatted date.","     *","     * @return string","     */","    public static function rfcDate()","    {","        //Set the time zone to whatever the default is to avoid 500 errors","        //Will default to UTC if it's not set properly in php.ini","        date_default_timezone_set(@date_default_timezone_get());","","        return date('D, j M Y H:i:s O');","    }","","    /**","     * Get the server hostname.","     * Returns 'localhost.localdomain' if unknown.","     *","     * @return string","     */","    protected function serverHostname()","    {","        $result = '';","        if (!empty($this-\u003eHostname)) {","            $result = $this-\u003eHostname;","        } elseif (isset($_SERVER) \u0026\u0026 array_key_exists('SERVER_NAME', $_SERVER)) {","            $result = $_SERVER['SERVER_NAME'];","        } elseif (function_exists('gethostname') \u0026\u0026 gethostname() !== false) {","            $result = gethostname();","        } elseif (php_uname('n') !== '') {","            $result = php_uname('n');","        }","        if (!static::isValidHost($result)) {","            return 'localhost.localdomain';","        }","","        return $result;","    }","","    /**","     * Validate whether a string contains a valid value to use as a hostname or IP address.","     * IPv6 addresses must include [], e.g. `[::1]`, not just `::1`.","     *","     * @param string $host The host name or IP address to check","     *","     * @return bool","     */","    public static function isValidHost($host)","    {","        //Simple syntax limits","        if (","            empty($host)","            || !is_string($host)","            || strlen($host) \u003e 256","            || !preg_match('/^([a-z\\d.-]*|\\[[a-f\\d:]+\\])$/i', $host)","        ) {","            return false;","        }","        //Looks like a bracketed IPv6 address","        if (strlen($host)