,"     * @return string The transformed message body","     *","     * @throws Exception","     *","     * @see PHPMailer::html2text()","     */","    public function msgHTML($message, $basedir = '', $advanced = false)","    {","        $cid_domain = 'phpmailer.0';","        if (filter_var($this-\u003eFrom, FILTER_VALIDATE_EMAIL)) {","            //prepend with a character to create valid RFC822 string in order to validate","            $cid_domain = substr($this-\u003eFrom, strrpos($this-\u003eFrom, '@') + 1);","        }","","        preg_match_all('/(?\u003c!-)(src|background)=[\"\\'](.*)[\"\\']/Ui', $message, $images);","        if (array_key_exists(2, $images)) {","            if (strlen($basedir) \u003e 1 \u0026\u0026 '/' !== substr($basedir, -1)) {","                //Ensure $basedir has a trailing /","                $basedir .= '/';","            }","            foreach ($images[2] as $imgindex =\u003e $url) {","                //Convert data URIs into embedded images","                //e.g. \"data:image/gif;base64,R0lGODlhAQABAAAAACH5BAEKAAEALAAAAAABAAEAAAICTAEAOw==\"","                $match = [];","                if (preg_match('#^data:(image/(?:jpe?g|gif|png));?(base64)?,(.+)#', $url, $match)) {","                    if (count($match) === 4 \u0026\u0026 static::ENCODING_BASE64 === $match[2]) {","                        $data = base64_decode($match[3]);","                    } elseif ('' === $match[2]) {","                        $data = rawurldecode($match[3]);","                    } else {","                        //Not recognised so leave it alone","                        continue;","                    }","                    //Hash the decoded data, not the URL, so that the same data-URI image used in multiple places","                    //will only be embedded once, even if it used a different encoding","                    $cid = substr(hash('sha256', $data), 0, 32) . '@' . $cid_domain; //RFC2392 S 2","","                    if (!$this-\u003