                    $this-\u003eaddEmbeddedImage(","                            $basedir . $directory . $filename,","                            $cid,","                            $filename,","                            static::ENCODING_BASE64,","                            static::_mime_types((string) static::mb_pathinfo($filename, PATHINFO_EXTENSION))","                        )","                    ) {","                        $message = preg_replace(","                            '/' . $images[1][$imgindex] . '=[\"\\']' . preg_quote($url, '/') . '[\"\\']/Ui',","                            $images[1][$imgindex] . '=\"cid:' . $cid . '\"',","                            $message","                        );","                    }","                }","            }","        }","        $this-\u003eisHTML();","        //Convert all message body line breaks to LE, makes quoted-printable encoding work much better","        $this-\u003eBody = static::normalizeBreaks($message);","        $this-\u003eAltBody = static::normalizeBreaks($this-\u003ehtml2text($message, $advanced));","        if (!$this-\u003ealternativeExists()) {","            $this-\u003eAltBody = 'This is an HTML-only message. To view it, activate HTML in your email application.'","                . static::$LE;","        }","","        return $this-\u003eBody;","    }","","    /**","     * Convert an HTML string into plain text.","     * This is used by msgHTML().","     * Note - older versions of this function used a bundled advanced converter","     * which was removed for license reasons in #232.","     * Example usage:","     *","     * ```php","     * //Use default conversion","     * $plain = $mail-\u003ehtml2text($html);","     * //Use your own custom converter","     * $plain = $mail-\u003ehtml2text($html, function($html) {","     *     $converter = new MyHtml2text($html);","     *     return $converter-\u003eget_text();","     * });","     * ```","     *","     * @param string        $html     The HTML text to convert","     * @param bool|callable $advanced Any boolean value to use the internal converter,","     *                                or provide your own callable for custom conversion.","     *                                *Never* pass user-supplied data into this parameter","     *","     * @return string","     */","    public function html2text($html, $advanced = false)","    {","        if (is_callable($advanced)) {","            return call_user_func($advanced, $html);","        }","","        return html_entity_decode(","            trim(strip_tags(preg_replace('/\u003c(head|title|style|script)[^\u003e]*\u003e.*?\u003c\\/\\\\1\u003e/si', '', $html))),","            ENT_QUOTES,","            $this-\u003eCharSet","        );","    }","","    /**","     * Get the MIME type for a file extension.","     *","     * @param string $ext File extension","     *","     * @return string MIME type of file","     */","    public static function _mime_types($ext = '')","    {","        $mimes = [","            'xl' =\u003e 'application/excel',","            'js' =\u003e 'application/javascript',","            'hqx' =\u003e 'application/mac-binhex40',","            'cpt' =\u003e 'application/mac-compactpro',","            'bin' =\u003e 'application/macbinary',","            'doc' =\u003e 'application/msword',","            'word' =\u003e 'application/msword',","            'xlsx' =\u003e 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',","            'xltx' =\u003e 'application/vnd.openxmlformats-officedocument.spreadsheetml.template',","            'potx' =\u003e 'application/vnd.openxmlformats-officedocument.presentationml.template',","            'ppsx' =\u003e 'application/vnd.openxmlformats-officedocument.presentationml.slideshow',","            'pptx' =\u003e 'application/vnd.openxmlformats-officedocument.presentationml.presentation',","            'sldx' =\u003e 'application/vnd.openxmlformats-officedocument.presentationml.