      'text' =\u003e 'text/plain',","            'txt' =\u003e 'text/plain',","            'rtx' =\u003e 'text/richtext',","            'rtf' =\u003e 'text/rtf',","            'vcf' =\u003e 'text/vcard',","            'vcard' =\u003e 'text/vcard',","            'ics' =\u003e 'text/calendar',","            'xml' =\u003e 'text/xml',","            'xsl' =\u003e 'text/xml',","            'csv' =\u003e 'text/csv',","            'wmv' =\u003e 'video/x-ms-wmv',","            'mpeg' =\u003e 'video/mpeg',","            'mpe' =\u003e 'video/mpeg',","            'mpg' =\u003e 'video/mpeg',","            'mp4' =\u003e 'video/mp4',","            'm4v' =\u003e 'video/mp4',","            'mov' =\u003e 'video/quicktime',","            'qt' =\u003e 'video/quicktime',","            'rv' =\u003e 'video/vnd.rn-realvideo',","            'avi' =\u003e 'video/x-msvideo',","            'movie' =\u003e 'video/x-sgi-movie',","            'webm' =\u003e 'video/webm',","            'mkv' =\u003e 'video/x-matroska',","        ];","        $ext = strtolower($ext);","        if (array_key_exists($ext, $mimes)) {","            return $mimes[$ext];","        }","","        return 'application/octet-stream';","    }","","    /**","     * Map a file name to a MIME type.","     * Defaults to 'application/octet-stream', i.e.. arbitrary binary data.","     *","     * @param string $filename A file name or full path, does not need to exist as a file","     *","     * @return string","     */","    public static function filenameToType($filename)","    {","        //In case the path is a URL, strip any query string before getting extension","        $qpos = strpos($filename, '?');","        if (false !== $qpos) {","            $filename = substr($filename, 0, $qpos);","        }","        $ext = static::mb_pathinfo($filename, PATHINFO_EXTENSION);","","        return static::_mime_types($ext);","    }","","    /**","     * Multi-byte-safe pathinfo replacement.","     * Drop-in replacement for pathinfo(), but multibyte- and cross-platform-safe.","     *","     * @see https://www.php.net/manual/en/function.pathinfo.php#107461","     *","     * @param string     $path    A filename or path, does not need to exist as a file","     * @param int|string $options Either a PATHINFO_* constant,","     *                            or a string name to return only the specified piece","     *","     * @return string|array","     */","    public static function mb_pathinfo($path, $options = null)","    {","        $ret = ['dirname' =\u003e '', 'basename' =\u003e '', 'extension' =\u003e '', 'filename' =\u003e ''];","        $pathinfo = [];","        if (preg_match('#^(.*?)[\\\\\\\\/]*(([^/\\\\\\\\]*?)(\\.([^.\\\\\\\\/]+?)|))[\\\\\\\\/.]*$#m', $path, $pathinfo)) {","            if (array_key_exists(1, $pathinfo)) {","                $ret['dirname'] = $pathinfo[1];","            }","            if (array_key_exists(2, $pathinfo)) {","                $ret['basename'] = $pathinfo[2];","            }","            if (array_key_exists(5, $pathinfo)) {","                $ret['extension'] = $pathinfo[5];","            }","            if (array_key_exists(3, $pathinfo)) {","                $ret['filename'] = $pathinfo[3];","            }","        }","        switch ($options) {","            case PATHINFO_DIRNAME:","            case 'dirname':","                return $ret['dirname'];","            case PATHINFO_BASENAME:","            case 'basename':","                return $ret['basename'];","            case PATHINFO_EXTENSION:","            case 'extension':","                return $ret['extension'];","            case PATHINFO_FILENAME:","            case 'filename':","                return $ret['filename'];","            default:","                return $ret;","        }","    }","","    /**","     * Set or reset instance properties.","     * You should avoid this function - it's more verbose, less efficient, more error-prone and","     * harder to debug than setting properties directly.","     * Usage Example:","     * `$mail-\u003eset('SMTPSecure', static::ENCRYPTION_STARTTLS);`","     *   is the same as:","     * `$mail-\u003eSMTPSecure = static::ENCRYPTION_STARTTLS;`.","     *","     * @param string $name  The property name to set","     * @param mixed  $value The value to set the property to","     *","     * @return bool","     */","    public function set($name, $value = '')","    {","        if (property_exists($this, $name)) {","            $this-\u003e{$name} = $value;","","            return true;","        }","        $this-\u003esetError(self::lang('variable_set') . $name);","","        return false;","    }","","    /**","     * Strip newlines to prevent header injection.","     *","     * @param string $str","     *","     * @return string","     */","    public function secureHeader($str)","    {","        return trim(str_replace([\"\\r\", \"\\n\"], '', $str));","    }","","    /**","     * Normalize line breaks in a string.","     * Converts UNIX LF, Mac CR and Windows CRLF line breaks into a single line break format.","     * Defaults to CRLF (for message bodies) and preserves consecutive breaks.","     *","     * @param string $text","     * @param string $breaktype What kind of line break to use; defaults to static::$LE","     *","     * @return string","     */","    public static function normalizeBreaks($text, $breaktype = null)","    {","        if (null === $breaktype) {","            $breaktype = static::$LE;","        }","        //Normalise to \\n","        $text = str_replace([self::CRLF, \"\\r\"], \"\\n\", $text);","        //Now convert LE as needed","        if (\"\\n\" !== $breaktype) {","            $text = str_replace(\"\\n\", $breaktype, $text);","        }","","        return $text;","    }","","    /**","     * Remove trailing whitespace from a string.","     *","     * @param string $text","     *","     * @return string The text to remove whitespace from","     */","    public static function stripTrailingWSP($text)","    {","        return rtrim($text, \" \\r\\n\\t\");","    }","","    /**","     * Strip trailing line breaks from a string.","     *","     * @param string $text","     *","     * @return string The text to remove breaks from","     */","    public static function stripTrailingBreaks($text)","    {","        return rtrim($text, \"\\r\\n\");","    }","","    /**","     * Return the current line break format string.","     *","     * @return string","     */","    public static function getLE()","    {","        return static::$LE;","    }","","    /**","     * Set the line break format string, e.g. \"\\r\\n\".","     *","     * @param string $le","     */","    protected static function setLE($le)","    {","        static::$LE = $le;","    }","","    /**","     * Set the public and private key files and password for S/MIME signing.","     *","     * @param string $cert_filename","     * @param string $key_filename","     * @param string $key_pass            Password for private key","     * @param string $extracerts_filename Optional path to chain certificate","     */","    public function sign($cert_filename, $key_filename, $key_pass, $extracerts_filename = '')","    {","        $this-\u003esign_cert_file = $cert_filename;","        $this-\u003esign_key_file = $key_filename;","        $this-\u003esign_key_pass = $key_pass;","        $this-\u003esign_extracerts_file = $extracerts_filename;","    }","","    /**","     * Quoted-Printable-encode a DKIM header.","     *","     * @param string $txt","     *","     * @return string","     */","    public function DKIM_QP($txt)","    {","        $line = '';","        $len = strlen($txt);","        for ($i = 0; $i \u003c $len; ++$i) {","            $ord = ord($txt[$i]);","            if (((0x21 \u003c= $ord) \u0026\u0026 ($ord \u003c= 0x3A)) || $ord === 0x3C || ((0x3E \u003c= $ord) \u0026\u0026 ($ord \u003c= 0x7E))) {","                $line .= $txt[$i];","            } else {","                $line .= '=' . sprintf('%02X', $ord);","            }","        }","","        return $line;","    }","","    /**","     * Generate a DKIM signature.","     *","     * @param string $signHeader","     *","     * @throws Exception","     *","     * @return string The DKIM signature value","     */","    public function DKIM_Sign($signHeader)","    {","        if (!defined('PKCS7_TEXT')) {","            if ($this-\u003eexceptions) {","                throw new Exception(self::lang('extension_missing') . 'openssl');","            }","","            return '';","        }","        $privKeyStr = !empty($this-\u003eDKIM_private_string) ?","            $this-\u003eDKIM_private_string :","            file_get_contents($this-\u003eDKIM_private);","        if ('' !== $this-\u003eDKIM_passphrase) {","            $privKey = openssl_pkey_get_private($privKeyStr, $this-\u003eDKIM_passphrase);","        } else {","            $privKey = openssl_pkey_get_private($privKeyStr);","        }","        if (openssl_sign($signHeader, $signature, $privKey, 'sha256WithRSAEncryption')) {","            if (\\PHP_MAJOR_VERSION \u003c 8) {","                // phpcs:ignore PHPCompatibility.FunctionUse.RemovedFunctions.openssl_pkey_freeDeprecated","                openssl_pkey_free($privKey);","            }","","            return base64_encode($signature);","        }","        if (\\PHP_MAJOR_VERSION \u003c 8) {","            // phpcs:ignore PHPCompatibility.FunctionUse.RemovedFunctions.openssl_pkey_freeDeprecated","            openssl_pkey_free($privKey);","        }","","        return '';","    }","","    /**","     * Generate a DKIM canonicalization header.","     * Uses the 'relaxed' algorithm from RFC6376 section 3.4.2.","     * Canonicalized headers should *always* use CRLF, regardless of mailer setting.","     *","     * @see https://www.rfc-editor.org/rfc/rfc6376#section-3.4.2","     *","     * @param string $signHeader Header","     *","     * @return string","     */","    public function DKIM_HeaderC($signHeader)","    {","        //Normalize breaks to CRLF (regardless of the mailer)","        $signHeader = static::normalizeBreaks($signHeader, self::CRLF);","        //Unfold header lines","        //Note PCRE \\s is too broad a definition of whitespace; RFC5322 defines it as `[ \\t]`","        //@see https://www.rfc-editor.org/rfc/rfc5322#section-2.2","        //That means this may break if you do something daft like put vertical tabs in your headers.","        $signHeader = preg_replace('/\\r\\n[ \\t]+/', ' ', $signHeader);","        //Break headers out into an array","        $lines = explode(self::CRLF, $signHeader);","        foreach ($lines as $key =\u003e $line) {","            //If the header is missing a :, skip it as it's invalid","            //This is likely to happen because the explode() above will also split","            //on the trailing LE, leaving an empty line","            if (strpos($line, ':') === false) {","                continue;","            }","            list($heading, $value) = explode(':', $line, 2);","            //Lower-case header name","            $heading = strtolower($heading);","            //Collapse white space within the value, also convert WSP to space","            $value = preg_replace('/[ \\t]+/', ' ', $value);","            //RFC6376 is slightly unclear here - it says to delete space at the *end* of each value","            //But then says to delete space before and after the colon.","            //Net result is the same as trimming both ends of the value.","            //By elimination, the same applies to the field name","            $lines[$key] = trim($heading, \" \\t\") . ':' . trim($value, \" \\t\");","        }","","        return implode(self::CRLF, $lines);","    }","","    /**","     * Generate a DKIM canonicalization body.","     * Uses the 'simple' algorithm from RFC6376 section 3.4.3.","     * Canonicalized bodies should *always* use CRLF, regardless of mailer setting.","     *","     * @see https://www.rfc-editor.org/rfc/rfc6376#section-3.4.3","     *","     * @param string $body Message Body","     *","     * @return string","     */","    public function DKIM_BodyC($body)","    {","        if (empty($body)) {","            return self::CRLF;","        }","        //Normalize line endings to CRLF","        $body = static::normalizeBreaks($body, self::CRLF);","","        //Reduce multiple trailing line breaks to a single one","        return static::stripTrailingBreaks($body) . self::CRLF;","    }","","    /**","     * Create the DKIM header and body in a new message header.","     *","     * @param string $headers_line Header lines","     * @param string $subject      Subject","     * @param string $body         Body","     *","     * @throws Exception","     *","     * @return string","     */","    public function DKIM_Add($headers_line, $subject, $body)","    {","        $DKIMsignatureType = 'rsa-sha256'; //Signature \u0026 hash algorithms","        $DKIMcanonicalization = 'relaxed/simple'; //Canonicalization methods of header \u0026 body","        $DKIMquery = 'dns/txt'; //Query method","        $DKIMtime = time();","        //Always sign these headers without being asked","        //Recommended list from https://www.rfc-editor.org/rfc/rfc6376#section-5.4.1","        $autoSignHeaders = [","            'from',","            'to',","            'cc',","            'date',","            'subject',","            'reply-to',","            'message-id',","            'content-type',","            'mime-version',","            'x-mailer',","        ];","        if (stripos($headers_line, 'Subject') === false) {","            $headers_line .= 'Subject: ' . $subject . static::$LE;","        }","        $headerLines = explode(static::$LE, $headers_line);","        $currentHeaderLabel = '';","        $currentHeaderValue = '';","        $parsedHeaders = [];","        $headerLineIndex = 0;","        $headerLineCount = count($headerLines);","        foreach ($headerLines as $headerLine) {","            $matches = [];","            if (preg_match('/^([^ \\t]*?)(?::[ \\t]*)(.*)$/', $headerLine, $matches)) {","                if ($currentHeaderLabel !== '') {","                    //We were previously in another header; This is the start of a new header, so save the previous one","                    $parsedHeaders[] = ['label' =\u003e $currentHeaderLabel, 'value' =\u003e $currentHeaderValue];","                }","                $currentHeaderLabel = $matches[1];","                $currentHeaderValue = $matches[2];","            } elseif (preg_match('/^[ \\t]+(.*)$/', $headerLine, $matches)) {","                //This is a folded continuation of the current header, so unfold it","                $currentHeaderValue .= ' ' . $matches[1];","            }","            ++$headerLineIndex;","            if ($headerLineIndex \u003e= $headerLineCount) {","                //This was the last line, so finish off this header","                $parsedHeaders[] = ['label' =\u003e $currentHeaderLabel, 'value' =\u003e $currentHeaderValue];","            }","        }","        $copiedHeaders = [];","        $headersToSignKeys = [];","        $headersToSign = [];","        foreach ($parsedHeaders as $header) {","            //Is this header one that must be included in the DKIM signature?","            if (in_array(strtolower($header['label']), $autoSignHeaders, true)) {","                $headersToSignKeys[] = $header['label'];","                $headersToSign[] = $header['label'] . ': ' . $header['value'];","                if ($this-\u003eDKIM_copyHeaderFields) {","                    $copiedHeaders[] = $header['label'] . ':' . //Note no space after this, as per RFC","                        str_replace('|', '=7C', $this-\u003eDKIM_QP($header['value']));","                }","                continue;","            }","            //Is this an extra custom header we've been asked to sign?","            if (in_array($header['labe